package com.evolua.notification.infrastructure.persistence; import com.evolua.notification.domain.NotificationJob; import com.evolua.notification.domain.NotificationJobRepository; import com.fasterxml.jackson.databind.ObjectMapper; import java.util.ArrayList; import java.util.List; import org.springframework.data.redis.core.StringRedisTemplate; import org.springframework.stereotype.Repository; @Repository public class NotificationJobRedisRepository implements NotificationJobRepository { private final StringRedisTemplate redisTemplate; private final ObjectMapper objectMapper; public NotificationJobRedisRepository(StringRedisTemplate redisTemplate, ObjectMapper objectMapper) { this.redisTemplate = redisTemplate; this.objectMapper = objectMapper; } public NotificationJob save(NotificationJob item) { try { redisTemplate.opsForList().rightPush("notification-jobs:" + item.userId(), objectMapper.writeValueAsString(item)); return item; } catch (Exception ex) { throw new IllegalArgumentException("Could not save notification"); } } public List<NotificationJob> findAllByUserId(String userId) { List<String> rows = redisTemplate.opsForList().range("notification-jobs:" + userId, 0, -1); if (rows == null) { return List.of(); } List<NotificationJob> result = new ArrayList<>(); for (String row : rows) { try { result.add(objectMapper.readValue(row, NotificationJob.class)); } catch (Exception ex) { throw new IllegalArgumentException("Could not parse notification"); } } return result; } }
